async function downloadFile(name) {
    const fullPath = currentVaultPath ? `${currentVaultPath}/${name}` : name;

    // 1. Open a 'Proxy' window immediately to satisfy browser security (Pop-up blocker)
    const proxyWin = window.open("", "_blank");
    proxyWin.document.write("<style>body{background:#050505;color:#00f3ff;font-family:monospace;display:flex;justify-content:center;align-items:center;height:100vh;margin:0;} </style><div>PREPARING ENCRYPTED STREAM...</div>");

    toast("AUTHORIZING DOWNLOAD...", "success");

    const { data, error } = await sb.storage
        .from('cortex-vault')
        .createSignedUrl(fullPath, 60);

    if (error || !data?.signedUrl) {
        proxyWin.close();
        return toast("VAULT ERROR: " + (error?.message || "Access Denied"), "danger");
    }

    // 2. Redirect the proxy window to the signed URL
    // We use location.replace to ensure the browser treats it as a file download trigger
    proxyWin.location.replace(data.signedUrl);

    // 3. Auto-close the proxy window after a delay (enough for the download to start)
    setTimeout(() => {
        if (proxyWin && !proxyWin.closed) proxyWin.close();
    }, 5000);
}

