ops.replace_with:
async function downloadFile(name) {
    const fullPath = currentVaultPath ? `${currentVaultPath}/${name}` : name;

    toast("RETRIEVING ENCRYPTED BLOB...", "success");

    // Download the file directly as a Blob
    const { data, error } = await sb.storage
        .from('cortex-vault')
        .download(fullPath);

    if (error) {
        console.error("Download Error:", error);
        return toast("VAULT ERROR: " + error.message, "danger");
    }

    if (data) {
        // Create a local URL for the downloaded blob
        const url = window.URL.createObjectURL(data);
        const a = document.createElement('a');
        a.style.display = 'none';
        a.href = url;
        a.download = name; // Force the filename
        document.body.appendChild(a);
        a.click();

        // Cleanup
        setTimeout(() => {
            window.URL.revokeObjectURL(url);
            a.remove();
            toast("DECRYPTION & DOWNLOAD COMPLETE", "success");
        }, 100);
    } else {
        toast("FILE STREAM EMPTY", "danger");
    }
}

