async function downloadFile(name) {
    const fullPath = currentVaultPath ? `${currentVaultPath}/${name}` : name;
    console.log("[VAULT] Requesting download for:", fullPath);
    toast("PREPARING DATA...", "success");

    try {
        // 1. Get the signed URL
        const { data, error } = await sb.storage
            .from('cortex-vault')
            .createSignedUrl(fullPath, 60);

        if (error) throw error;
        if (!data?.signedUrl) throw new Error("No signed URL returned");

        console.log("[VAULT] Signed URL generated. Fetching blob...");

        // 2. Fetch the file data as a blob (to force download on cross-origin)
        const response = await fetch(data.signedUrl);
        if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

        const blob = await response.blob();
        const blobUrl = window.URL.createObjectURL(blob);

        // 3. Create invisible anchor and trigger
        const link = document.createElement('a');
        link.href = blobUrl;
        link.setAttribute('download', name);
        document.body.appendChild(link);
        link.click();

        // 4. Cleanup
        setTimeout(() => {
            document.body.removeChild(link);
            window.URL.revokeObjectURL(blobUrl);
        }, 100);

        console.log("[VAULT] Download triggered for:", name);
        toast("DOWNLOAD STARTED", "success");
    } catch (err) {
        console.error("[VAULT_ERROR]", err);
        toast("DOWNLOAD FAILED: " + err.message, "danger");
    }
}

